// すべての入力アイテムを取得します
const items = $input.all();

// 1. 各アイテムのJSONデータを抽出
const allJsonData = items.map(item => item.json);

// 2. 「順位」が30以下のアイテムのみにフィルタリング
//    - parseInt() を使って、文字列の可能性がある「順位」を確実に数値として比較します
const filteredData = allJsonData.filter(item => parseInt(item['順位'], 10) <= 30);

// 3. 念のため「順位」の昇順で並び替え
//    - 元データが順位順でない可能性も考慮してソートします
const sortedData = filteredData.sort((a, b) => parseInt(a['順位'], 10) - parseInt(b['順位'], 10));

// 4. 上位30件（またはそれ以下）のデータを'all_contents'として出力
return [
  {
    json: {
      all_contents: sortedData
    }
  }
];
